import json, re, glob, collections
DOI_RE = re.compile(r'10\.\d{4,9}/[-._;()/:A-Za-z0-9]+')
KNOWN = {'aeaweb.org','sciencedirect.com','link.springer.com','cambridge.org','emerald.com','nber.org','onlinelibrary.wiley.com','tandfonline.com','journals.sagepub.com','academic.oup.com','mdpi.com','arxiv.org','papers.ssrn.com','ideas.repec.org','econstor.eu','cepr.org','pmc.ncbi.nlm.nih.gov','pubmed.ncbi.nlm.nih.gov','revistes.ub.edu','econbiz.de','siepr.stanford.edu','economics.mit.edu','nature.com','bls.gov','congress.gov','oecd.org','imf.org','ilo.org','openknowledge.worldbank.org','newyorkfed.org','federalreserve.gov','brookings.edu','reports.weforum.org','weforum.org','whitehouse.gov','goldmansachs.com','mckinsey.com','hbsp.harvard.edu','shrm-res.cloudinary.com','en.wikipedia.org','static1.squarespace.com','ssir.org','medium.com'}
def dom(u):
    p=str(u or '').split('/'); return p[2].replace('www.','') if len(p)>2 and str(u).startswith('http') else ''
def rows_from(o,acc):
    if isinstance(o,dict):
        if o.get('direct_quote') is not None and (o.get('source_url') or o.get('url')): acc.append(o)
        for v in o.values(): rows_from(v,acc)
    elif isinstance(o,list):
        for x in o: rows_from(x,acc)
# Find a bug-state cp2 (raw evidence rows) to demonstrate residual violations
cands = glob.glob('/home/polaris/wt/s2s3/outputs/**/cp2_corpus_snapshot.json',recursive=True)
print("cp2 candidates:", len(cands))
for path in sorted(cands):
    d=json.load(open(path))
    rows=[r for r in d.get('evidence_for_gen',[]) if isinstance(r,dict)]
    if not rows: 
        acc=[]; rows_from(d,acc); rows=acc
    doi_viol=[r for r in rows if not str(r.get('doi','') or '').strip() and (DOI_RE.search(str(r.get('direct_quote','') or '')) or DOI_RE.search(str(r.get('source_url') or r.get('url') or '')))]
    tier_viol=[r for r in rows if str(r.get('tier') or 'UNKNOWN')=='UNKNOWN' and dom(r.get('source_url') or r.get('url')) in KNOWN]
    has_meta = 'metadata_enrichment_summary' in d
    # false-positive candidates: rows with NO doi anywhere (legit) must NOT be flagged
    no_doi_legit=[r for r in rows if not (DOI_RE.search(str(r.get('direct_quote','') or '')) or DOI_RE.search(str(r.get('source_url') or r.get('url') or '')))]
    print(f"{path.split('s2s3/')[-1]:55s} rows={len(rows):4d} enrich_summary={has_meta} DOI_residual_violations={len(doi_viol):3d} tier_residual_violations={len(tier_viol):3d} legit_no_doi_rows={len(no_doi_legit)}")
